                        Analyzing...
                      </div>
                    </div>
                  )}
                </div>

                <form onSubmit={handleRefine} className="p-4 bg-gray-900 border-t border-gray-800">
                  <div className="relative">
                    <input
                      value={chatInput}
                      onChange={(e) => setChatInput(e.target.value)}
