                </button>
              ))}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {APP_TYPES.map((item) => (
                <button
                  key={item.type}
                  onClick={() => setAppType(item.type)}
