// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/**
 * @title DiamondAnalytics
 * @dev Real-time analytics and monitoring for high-density Diamond Proxy systems
 * Provides performance tracking, alerting, and optimization insights for 275+ facets
 */
contract DiamondAnalytics {

    // ==================== Storage ====================

    address public diamond;

    // Real-time metrics
    mapping(bytes4 => SelectorMetrics) public selectorMetrics;
    mapping(address => FacetMetrics) public facetMetrics;
    mapping(string => SystemMetrics) public systemMetrics;

    // Historical data (circular buffers to manage storage)
    mapping(bytes4 => uint256[]) public selectorGasHistory;
    mapping(address => uint256[]) public facetCallHistory;

    // Alert thresholds and configuration
    mapping(string => AlertThreshold) public alertThresholds;
    mapping(bytes32 => Alert) public activeAlerts;

    // Performance optimization data
    mapping(bytes4 => bytes4[]) public hotPathClusters;
    mapping(address => OptimizationSuggestion) public optimizationSuggestions;

    // ==================== Structs ====================

    struct SelectorMetrics {
        uint256 totalCalls;
        uint256 totalGas;
        uint256 averageGas;
        uint256 minGas;
        uint256 maxGas;
        uint256 lastCalled;
        uint256 callFrequency; // calls per hour
        uint256 hotPathScore;
        bool isHotPath;
    }

    struct FacetMetrics {
        uint256 totalCalls;
        uint256 totalGas;
        uint256 averageGas;
        uint256 selectorCount;
        uint256 deploymentTime;
        uint256 lastUpgrade;
        uint256 utilizationScore;
        bool isOptimized;
    }

    struct SystemMetrics {
        uint256 totalFacets;
        uint256 totalSelectors;
        uint256 totalCalls;
        uint256 totalGas;
        uint256 averageGasPerCall;
        uint256 uptime;
        uint256 lastUpdate;
        uint256 efficiencyScore;
    }

    struct AlertThreshold {
        uint256 highGasThreshold;
        uint256 lowFrequencyThreshold;
        uint256 performanceDegradationThreshold;
        uint256 anomalyDetectionSensitivity;
        bool isActive;
    }

    struct Alert {
        string alertType;
        bytes4 selector;
        address facet;
        uint256 metricValue;
        uint256 timestamp;
        string description;
        bool isActive;
    }

    struct OptimizationSuggestion {
        string suggestionType;
        uint256 potentialGasSaving;
        uint256 confidenceScore;
        string description;
        bytes4[] relatedSelectors;
        bool isImplemented;
    }

    // ==================== Events ====================

    event MetricUpdated(string metricType, bytes4 indexed selector, address indexed facet, uint256 value);
    event AlertTriggered(string alertType, bytes4 indexed selector, address indexed facet, uint256 value);
    event OptimizationIdentified(string suggestionType, uint256 potentialSaving, bytes4[] selectors);
    event PerformanceReportGenerated(uint256 timestamp, uint256 totalFacets, uint256 efficiencyScore);

    // ==================== Constructor ====================

    constructor(address _diamond) {
        diamond = _diamond;
        _initializeDefaultThresholds();
    }

    // ==================== Core Analytics ====================

    /**
     * @dev Update selector metrics from Diamond proxy
     */
    function updateSelectorMetrics(bytes4 selector, uint256 gasUsed, address facet) external {
        require(msg.sender == diamond, "Only diamond can update metrics");

        SelectorMetrics storage metrics = selectorMetrics[selector];

        // Update basic metrics
        metrics.totalCalls++;
        metrics.totalGas += gasUsed;
        metrics.lastCalled = block.timestamp;

        // Calculate rolling average
        metrics.averageGas = metrics.totalGas / metrics.totalCalls;

        // Update min/max gas
        if (metrics.minGas == 0 || gasUsed < metrics.minGas) {
            metrics.minGas = gasUsed;
        }
        if (gasUsed > metrics.maxGas) {
            metrics.maxGas = gasUsed;
        }

        // Calculate call frequency (calls per hour)
        uint256 timeSinceLastCall = block.timestamp - metrics.lastCalled;
        if (timeSinceLastCall > 0) {
            metrics.callFrequency = 3600 / timeSinceLastCall; // calls per hour
        }

        // Update hot path status
        _updateHotPathStatus(selector);

        // Store gas history (keep last 100 readings)
        if (selectorGasHistory[selector].length >= 100) {
            // Remove oldest reading (circular buffer)
            for (uint256 i = 0; i < selectorGasHistory[selector].length - 1; i++) {
                selectorGasHistory[selector][i] = selectorGasHistory[selector][i + 1];
            }
            selectorGasHistory[selector].pop();
        }
        selectorGasHistory[selector].push(gasUsed);

        // Check for alerts
        _checkSelectorAlerts(selector, gasUsed);

        emit MetricUpdated("selector", selector, facet, gasUsed);
    }

    /**
     * @dev Update facet metrics
     */
    function updateFacetMetrics(address facet, uint256 gasUsed, bytes4 selector) external {
        require(msg.sender == diamond, "Only diamond can update metrics");

        FacetMetrics storage metrics = facetMetrics[facet];

        metrics.totalCalls++;
        metrics.totalGas += gasUsed;
        metrics.averageGas = metrics.totalGas / metrics.totalCalls;

        // Update utilization score
        metrics.utilizationScore = (metrics.totalCalls * 100) / block.timestamp;

        // Store call history
        if (facetCallHistory[facet].length >= 100) {
            for (uint256 i = 0; i < facetCallHistory[facet].length - 1; i++) {
                facetCallHistory[facet][i] = facetCallHistory[facet][i + 1];
            }
            facetCallHistory[facet].pop();
        }
        facetCallHistory[facet].push(gasUsed);

        emit MetricUpdated("facet", selector, facet, gasUsed);
    }

    /**
     * @dev Update system-wide metrics
     */
    function updateSystemMetrics() external {
        SystemMetrics storage metrics = systemMetrics["current"];

        metrics.totalFacets = getActiveFacetCount();
        metrics.totalSelectors = getActiveSelectorCount();
        metrics.totalCalls = getTotalCalls();
        metrics.totalGas = getTotalGas();
        metrics.averageGasPerCall = metrics.totalCalls > 0 ? metrics.totalGas / metrics.totalCalls : 0;
        metrics.lastUpdate = block.timestamp;
        metrics.uptime = block.timestamp - deploymentTime();

        // Calculate efficiency score (0-1000 scale)
        metrics.efficiencyScore = calculateEfficiencyScore();

        emit MetricUpdated("system", bytes4(0), address(0), metrics.efficiencyScore);
    }

    // ==================== Performance Analysis ====================

    /**
     * @dev Identify optimization opportunities
     */
    function identifyOptimizations() external returns (OptimizationSuggestion[] memory suggestions) {
        suggestions = new OptimizationSuggestion[](50); // Max 50 suggestions
        uint256 suggestionCount = 0;

        // Analyze hot paths
        bytes4[] memory hotSelectors = getHotPathSelectors();

        for (uint256 i = 0; i < hotSelectors.length && suggestionCount < 50; i++) {
            OptimizationSuggestion memory suggestion = _analyzeSelectorOptimization(hotSelectors[i]);
            if (suggestion.potentialGasSaving > 10000) { // 10k+ gas saving
                suggestions[suggestionCount] = suggestion;
                suggestionCount++;

                emit OptimizationIdentified(
                    suggestion.suggestionType,
                    suggestion.potentialGasSaving,
                    suggestion.relatedSelectors
                );
            }
        }

        // Resize array to actual count
        assembly {
            mstore(suggestions, suggestionCount)
        }

        return suggestions;
    }

    /**
     * @dev Generate performance report
     */
    function generatePerformanceReport() external returns (string memory report) {
        SystemMetrics memory system = systemMetrics["current"];

        // Get top performers and underperformers
        bytes4[] memory topSelectors = getTopSelectorsByGasEfficiency(10);
        bytes4[] memory inefficientSelectors = getInefficientSelectors(10);

        // Build report
        report = string(abi.encodePacked(
            "=== Diamond Performance Report ===\n",
            "Generated: ", uint2str(block.timestamp), "\n",
            "Total Facets: ", uint2str(system.totalFacets), "\n",
            "Total Selectors: ", uint2str(system.totalSelectors), "\n",
            "Total Calls: ", uint2str(system.totalCalls), "\n",
            "Average Gas/Call: ", uint2str(system.averageGasPerCall), "\n",
            "Efficiency Score: ", uint2str(system.efficiencyScore), "/1000\n",
            "Uptime: ", uint2str(system.uptime), " seconds\n",
            "\n=== Top Performers ===\n",
            _formatSelectorList(topSelectors),
            "\n=== Needs Optimization ===\n",
            _formatSelectorList(inefficientSelectors),
            "\n=== Hot Paths ===\n",
            _formatSelectorList(getHotPathSelectors())
        ));

        emit PerformanceReportGenerated(block.timestamp, system.totalFacets, system.efficiencyScore);

        return report;
    }

    // ==================== Alert Management ====================

    /**
     * @dev Set alert thresholds
     */
    function setAlertThreshold(
        string memory alertType,
        uint256 highGasThreshold,
        uint256 lowFrequencyThreshold,
        uint256 performanceThreshold,
        uint256 sensitivity
    ) external {
        alertThresholds[alertType] = AlertThreshold({
            highGasThreshold: highGasThreshold,
            lowFrequencyThreshold: lowFrequencyThreshold,
            performanceDegradationThreshold: performanceThreshold,
            anomalyDetectionSensitivity: sensitivity,
            isActive: true
        });
    }

    /**
     * @dev Check and trigger alerts
     */
    function _checkSelectorAlerts(bytes4 selector, uint256 gasUsed) internal {
        AlertThreshold memory thresholds = alertThresholds["default"];
        if (!thresholds.isActive) return;

        // High gas usage alert
        if (gasUsed > thresholds.highGasThreshold) {
            _triggerAlert("HIGH_GAS", selector, address(0), gasUsed, "High gas usage detected");
        }

        // Anomaly detection
        if (_detectAnomaly(selector, gasUsed, thresholds.anomalyDetectionSensitivity)) {
            _triggerAlert("ANOMALY", selector, address(0), gasUsed, "Anomalous gas usage detected");
        }
    }

    /**
     * @dev Trigger alert
     */
    function _triggerAlert(
        string memory alertType,
        bytes4 selector,
        address facet,
        uint256 value,
        string memory description
    ) internal {
        bytes32 alertId = keccak256(abi.encodePacked(alertType, selector, facet, block.timestamp));

        activeAlerts[alertId] = Alert({
            alertType: alertType,
            selector: selector,
            facet: facet,
            metricValue: value,
            timestamp: block.timestamp,
            description: description,
            isActive: true
        });

        emit AlertTriggered(alertType, selector, facet, value);
    }

    // ==================== Helper Functions ====================

    /**
     * @dev Calculate efficiency score (0-1000)
     */
    function calculateEfficiencyScore() public view returns (uint256) {
        SystemMetrics memory system = systemMetrics["current"];

        if (system.totalCalls == 0) return 0;

        // Base score from gas efficiency
        uint256 gasScore = 1000 - (system.averageGasPerCall / 1000); // Normalize

        // Bonus for high utilization
        uint256 utilizationBonus = (system.totalFacets * 100) / 275; // Assuming 275 target

        // Penalty for inactive facets
        uint256 inactivePenalty = (getInactiveFacetCount() * 50) / system.totalFacets;

        return gasScore + utilizationBonus - inactivePenalty;
    }

    /**
     * @dev Update hot path status
     */
    function _updateHotPathStatus(bytes4 selector) internal {
        SelectorMetrics storage metrics = selectorMetrics[selector];

        // Hot path criteria: >100 calls and >10 calls per hour
        bool wasHotPath = metrics.isHotPath;
        metrics.isHotPath = metrics.totalCalls > 100 && metrics.callFrequency > 10;

        if (metrics.isHotPath && !wasHotPath) {
            // New hot path detected
            _optimizeHotPath(selector);
        }
    }

    /**
     * @dev Optimize hot path
     */
    function _optimizeHotPath(bytes4 selector) internal {
        // Identify related selectors (same facet, similar function patterns)
        address facet = getFacetForSelector(selector);
        bytes4[] memory relatedSelectors = getFacetSelectors(facet);

        hotPathClusters[selector] = relatedSelectors;

        // Generate optimization suggestion
        optimizationSuggestions[facet] = OptimizationSuggestion({
            suggestionType: "HOT_PATH_CLUSTERING",
            potentialGasSaving: 15000, // Estimated 15k gas saving
            confidenceScore: 85,
            description: "Cluster hot path selectors for better cache efficiency",
            relatedSelectors: relatedSelectors,
            isImplemented: false
        });
    }

    /**
     * @dev Detect performance anomalies
     */
    function _detectAnomaly(bytes4 selector, uint256 currentGas, uint256 sensitivity) internal view returns (bool) {
        SelectorMetrics memory metrics = selectorMetrics[selector];

        if (metrics.averageGas == 0) return false;

        uint256 deviation = currentGas > metrics.averageGas ? 
            ((currentGas - metrics.averageGas) * 100) / metrics.averageGas :
            ((metrics.averageGas - currentGas) * 100) / metrics.averageGas;

        return deviation > sensitivity;
    }

    /**
     * @dev Analyze selector optimization
     */
    function _analyzeSelectorOptimization(bytes4 selector) internal view returns (OptimizationSuggestion memory) {
        SelectorMetrics memory metrics = selectorMetrics[selector];

        if (metrics.totalCalls < 50) {
            return OptimizationSuggestion("", 0, 0, "", new bytes4[](0), false);
        }

        // Analyze gas usage patterns
        if (metrics.averageGas > 100000) {
            return OptimizationSuggestion({
                suggestionType: "HIGH_GAS_OPTIMIZATION",
                potentialGasSaving: metrics.averageGas * 20 / 100, // 20% saving
                confidenceScore: 75,
                description: "High gas usage detected, consider optimization",
                relatedSelectors: new bytes4[](0),
                isImplemented: false
            });
        }

        return OptimizationSuggestion("", 0, 0, "", new bytes4[](0), false);
    }

    /**
     * @dev Initialize default thresholds
     */
    function _initializeDefaultThresholds() internal {
        alertThresholds["default"] = AlertThreshold({
            highGasThreshold: 200000,
            lowFrequencyThreshold: 1,
            performanceDegradationThreshold: 50,
            anomalyDetectionSensitivity: 30,
            isActive: true
        });
    }

    /**
     * @dev Format selector list for reports
     */
    function _formatSelectorList(bytes4[] memory selectors) internal pure returns (string memory) {
        string memory result;
        for (uint256 i = 0; i < selectors.length && i < 5; i++) {
            result = string(abi.encodePacked(result, "  - ", selectorToString(selectors[i]), "\n"));
        }
        return result;
    }

    /**
     * @dev Convert selector to string
     */
    function selectorToString(bytes4 selector) internal pure returns (string memory) {
        bytes memory result = new bytes(10);
        result[0] = '0';
        result[1] = 'x';

        bytes32 value = bytes32(uint256(uint32(selector)));
        bytes memory alphabet = "0123456789abcdef";

        for (uint256 i = 0; i < 8; i++) {
            result[i + 2] = alphabet[uint8(value[i + 24] >> 4)];
            if (i * 2 + 1 < 8) {
                result[i * 2 + 3] = alphabet[uint8(value[i + 24] & 0x0f)];
            }
        }

        return string(result);
    }

    /**
     * @dev Convert uint to string
     */
    function uint2str(uint256 _i) internal pure returns (string memory) {
        if (_i == 0) {
            return "0";
        }
        uint256 j = _i;
        uint256 len;
        while (j != 0) {
            len++;
            j /= 10;
        }
        bytes memory bstr = new bytes(len);
        uint256 k = len;
        while (_i != 0) {
            k = k - 1;
            uint8 temp = (48 + uint8(_i - _i / 10 * 10));
            bytes1 b1 = bytes1(temp);
            bstr[k] = b1;
            _i /= 10;
        }
        return string(bstr);
    }

    // ==================== View Functions ====================

    function getActiveFacetCount() public view returns (uint256);
    function getActiveSelectorCount() public view returns (uint256);
    function getTotalCalls() public view returns (uint256);
    function getTotalGas() public view returns (uint256);
    function getInactiveFacetCount() public view returns (uint256);
    function getHotPathSelectors() public view returns (bytes4[] memory);
    function getTopSelectorsByGasEfficiency(uint256 count) public view returns (bytes4[] memory);
    function getInefficientSelectors(uint256 count) public view returns (bytes4[] memory);
    function getFacetForSelector(bytes4 selector) public view returns (address);
    function getFacetSelectors(address facet) public view returns (bytes4[] memory);
    function deploymentTime() public view returns (uint256);
}

